import React, { useEffect, useState } from "react";
import { Link } from "react-router-dom";
import "./test.css";

const typeDescriptions = {
  ENFP: "„აღმომჩენი“ - ენერგიული, კრეატიული და მხნე. უყვართ ახალი იდეები, ურთიერთობები და ადამიანების შთაგონება. გამოირჩევიან სხვების მხარდაჭერით, უშუალო კომუნიკაციითა და აქვთ გადამდები ენერგეტიკა.",
  ISTJ: "„ლოჯისტიკოსი“ - პრაქტიკული, საიმედო და დეტალებზე ორიენტირებული ადამიანი არიან, რომლებიც აფასებენ სტრუქტურას, წესრიგსა და პასუხისმგებლობას. ყოველთვის ასრულებენ დანაპირებს.",
  INFJ: "„მრჩეველი, იდეალისტი“ - სულიერად მდიდარი, შემოქმედებითი, მზრუნველი და გულწრფელი ადამიანები არიან. აფასებენ ურთიერთობებს, შთააგონებენ სხვებსა და არიან მოტივატორები.",
  ESFP: "„პერფორმერი“ - ენერგიული, მეგობრული და უშუალო ადამიანები არიან. სიამოვნებას იღებენ სხვების გარემოცვაში ყოფნით, რადგან უყვართ ყურადღების ცენტრში ყოფნა. არიან სპონტანურები, მხიარულები და ოპტიმისტურები.",
  INFP: "„მედიატორი“ - სულიერად მგრძნობიარე, იდეალისტი, შემოქმედებითი და ემპათიური ადამიანები არიან. მნიშვნელობას ანიჭებენ ადამიანურ ღირებულებებს და განსაკუთრებულ ყურადღებას უთმობენ ოჯახსა და ახლო მეგობრებს.",
  ESTJ: "„აღმსრულებელი, მმართველი“ - პრაქტიკული, პასუხისმგებლობით აღჭურვილი და ორგანიზებული ადამიანები არიან, რომლებიც აფასებენ წესრიგს, სტრუქტურასა და ტრადიციებს. გამოირჩევიან ლიდერული თვისებებით.",
  ENFJ: "„პროტაგონისტი“ - ენერგიული, ერთგული და კომუნიკაბელური ადამიანები არიან ძლიერი სოციალური ინტელექტით. ხშირად იღებენ პასუხისმგებლობას ჯგუფის კეთილდღეობაზე და უყვართ, როცა თავს საჭიროდ გრძნობენ.",
  ISFP: "„თავგადასავლების მოყვარული“ - მშვიდი, შემოქმედებითი და ბუნებაზე ორიენტირებული ადამიანები არიან. ცდილობენ თავი აარიდონ კონფლიქტს და შექმნან კომფორტული გარემო სხვებისთვის.",
  ISTP: "„ვირტუოზი“ - პრაქტიკული და ანალიტიკური ადამიანები არიან, რომლებიც სწრაფად პოულობენ გამოსავალს რეალურ სიტუაციებში და ადვილად ერგებიან ცვლილებებს.",
  ESFJ: "„კონსული“ - გულწრფელი, სოციალური და პასუხისმგებლობის მქონე ადამიანები არიან. ცდილობენ შექმნან ჰარმონიული გარემო და ითვალისწინებენ სხვების ინტერესებს.",
  ENTJ: "„კომანდირი“ - თავდაჯერებული, მიზანდასახული და სტრატეგიული ლიდერები არიან. სწრაფად იღებენ გადაწყვეტილებებს და ეფექტურად მართავენ გუნდებს.",
  INTJ: "„არქიტექტორი“ - სტრატეგიული და დამოუკიდებელი ადამიანები არიან, რომლებიც აფასებენ ლოგიკასა და ფაქტებს. მუდმივად ცდილობენ თვითგანვითარებას.",
  ESTP: "„მეწარმე“ - აქტიური და პრაქტიკულ აზროვნებაზე ორიენტირებული ადამიანები არიან, რომლებიც სწრაფად მოქმედებენ და სიამოვნებას იღებენ დინამიკით.",
  ENTP: "„ინოვატორი“ - ინტელექტუალური და კრეატიული ადამიანები არიან, რომლებიც მუდმივად ეძებენ ახალ იდეებსა და გამოცდილებას.",
  ISFJ: "„დამცველი“ - მზრუნველი და ერთგული ადამიანები არიან, რომლებიც განსაკუთრებულ ზრუნვას იჩენენ საყვარელი ადამიანების მიმართ.",
  INTP: "„ლოგიკოსი“ - ძლიერი ლოგიკური აზროვნებით გამორჩეული ადამიანები არიან, რომლებიც ინტერესდებიან თეორიული საკითხებით და პრობლემების ანალიზით.",
};

export default function FinalResult({ results }) {
  const [isLoggedIn, setIsLoggedIn] = useState(false);

  useEffect(() => {
    const token = localStorage.getItem("auth_token");
    if (token) setIsLoggedIn(true);
  }, []);

  const type =
    (results?.EI || "") +
    (results?.SN || "") +
    (results?.TF || "") +
    (results?.JP || "");

  const saveResult = () => {
    localStorage.setItem("savedResult", type);
    alert("შედეგი შენახულია ✅");
  };

  return (
    <div className="test-card">
      <img
        className="result-image"
        src={`/images/types/${type}.png`}
        alt={type}
      />

      <h2 style={{ marginTop: "20px" }}>{type}</h2>

      <p className="test-description">
        {typeDescriptions[type] ||
          "ეს არის მოკლე აღწერა თქვენს ფსიქოტიპზე."}
      </p>

      {isLoggedIn ? (
        <button
          onClick={saveResult}
          style={{
            marginTop: "20px",
            padding: "10px 25px",
            borderRadius: "30px",
            border: "none",
            cursor: "pointer",
            fontWeight: "600",
          }}
        >
          შედეგის შენახვა
        </button>
      ) : (
        <p style={{ marginTop: "20px" }}>
          შედეგის შენახვისთვის{" "}
          <Link to="/register" style={{ color: "#faf600" }}>
            გაიარე ავტორიზაცია
          </Link>
        </p>
      )}

      <p style={{ marginTop: "30px" }}>
        მეტი ინფორმაციისთვის გადადით{" "}
        <Link
          to="/articles"
          style={{ color: "#faf600", textDecoration: "underline" }}
        >
          მიმოხილვების
        </Link>{" "}
        გვერდზე
      </p>
    </div>
  );
}
